import{_ as s,c as p,o as n,ag as e}from"./chunks/framework.ELrfyV9R.js";const g=JSON.parse('{"title":"自动将本地markdown文档自动上传到推特后台","description":"","frontmatter":{"title":"自动将本地markdown文档自动上传到推特后台","cover_image":"../Gemini_Generated_Image_9paxk69paxk69pax.png"},"headers":[],"relativePath":"ai/2026-02/2026-02-07-post-x-skill/index.md","filePath":"ai/2026-02/2026-02-07-post-x-skill/index.md","lastUpdated":1773708953000}'),l={name:"ai/2026-02/2026-02-07-post-x-skill/index.md"};function i(t,a,o,d,r,c){return n(),p("div",null,a[0]||(a[0]=[e(`<p>中推AI圈里应该没人不知道宝玉的。这个男人可以说为中国普及AI或者说带动了中国部分热爱AI的人群，让他们在没有多少时间的情况，宝玉通过在推特和微信的分享，让无数中国爱好者能及时了解到ChatGPT、Gemini、Claude、Grok等等国外AI圈发展的情况，立下了汗马功劳，在下也会经常翻阅宝玉的文章进行反复的揣摩。</p><p>最近我进了一个叫前端哥的社群，请记住这个社群免费，付费的我加不起。</p><p>有一次聊天的时候发现很多人对推特的编辑器吐槽尤为厉害，尤其是长文，真的是灾难，有人甚至说终于见到比微信公众号编辑器还难用的了。不过话说回来我1月份写过几篇推特长文，确实体会到了其中的痛苦，于是我看到了宝玉的自动发推Skill。</p><p>我的感觉是所有人都可以试试。其实不难当然这里面的知识点我暂时就不进行讲解了，如果有人感兴趣，可以评论告诉我，我后面可以单独开一篇。</p><p>比如markdown的基础用法，可能很多人用过，也有很多人没用过。你去看看其实我常用的也就几个。</p><p>我一般就是标题‘##’, 正文就不管了， 特别需要注意的 &quot;&gt;&quot;。表格我一般直接用gemini 生成图片放进来。因为上传到推特后台后，表格的渲染是不会正确展示的，等等。</p><p>这里就不讲太多了，进入正题。也就是说要先准备一个包含图文的markdown文档，下面是我截图的markdown 文档预览。markdown</p><p>![[Pasted image 20260209151247.png]]</p><p>里面的图片也是在本地文件夹中的。</p><h2 id="准备skill" tabindex="-1">准备skill <a class="header-anchor" href="#准备skill" aria-label="Permalink to &quot;准备skill&quot;">​</a></h2><p>如果你是mac的话，可以直接打开这个网站 <a href="https://skills.sh/jimliu/baoyu-skills/baoyu-post-to-x" target="_blank" rel="noreferrer">https://skills.sh/jimliu/baoyu-skills/baoyu-post-to-x</a> ，复制里面的命令行直接安装即可。</p><blockquote><p>注意要在项目的根目录进行执行命令</p></blockquote><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npx skills add https://github.com/jimliu/baoyu-skills --skill baoyu-post-to-x</span></span></code></pre></div><p>宝玉的skill目前是不支持window的，所以我进行了变更 <a href="https://github.com/aehyok/Skills" target="_blank" rel="noreferrer">https://github.com/aehyok/Skills</a></p><p>其中的baoyu-post-to-x文件夹就是自动将本地markdown文档发送到推特草稿箱的skills，你可以将这个文件夹复制到对应的skills下。</p><p>我现在是一个项目下的skill就统一放到下图 .agents文件夹目录下，因为使用 npx skills 命令时他都会装到这个目录下。</p><p>![[Pasted image 20260209103950.png]]</p><p>因为我平时使用OpenCode、Codex、google antigravity比较多，所以只需要进行设置软连接就可以了，维护的话只需要维护一份，就是我上图中.agents 目录，其他使用最终都会指向.agnets目录。</p><p>软连接是用来干嘛的呢？ 先打个比方，A文件夹和B文件夹。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// window下 相当于访问A最终访问B，就不用在每个 .claude、 .opencode、codex、.agent等等文件夹在单独再拷贝一份Skill，而且维护的时候也方便</span></span>
<span class="line"><span></span></span>
<span class="line"><span>mklink /D A B</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// window下 使用codex的时候就会去访问.agnet</span></span>
<span class="line"><span>mklink /D .codex  .agents</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>// mac下,写法刚好和window下相反,要像下面这样写， 访问A最终才会访问B</span></span>
<span class="line"><span>ln -s B A </span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 其他类似了</span></span></code></pre></div><p>![[Pasted image 20260209110702.png]]</p><p>第一个是google antigravity使用的agent skill目录</p><p>这里相当于也给你简单介绍了如何管理自己一个项目中的skill。</p><h2 id="开干" tabindex="-1">开干 <a class="header-anchor" href="#开干" aria-label="Permalink to &quot;开干&quot;">​</a></h2><p>现在相当于skill准备好了，也准备好了文章。下面我是在OpenCode中进行操作的</p><p>在OpenCode客户端使用@便可以找到我们要</p><p>![[Pasted image 20260209112953.png]]</p><p>执行之后会弹出浏览器进行登录授权</p><p>![[Pasted image 20260209114150.png]]</p><p>登录完，你关闭浏览器，你的登录信息就在本地进行存储了，一段时间之内就不需要进行再次登录了。</p><p>如果跳转到下面页面也没关系，你点击搜索进入登录就可以了。</p><p>![[Pasted image 20260209151623.png]]</p><p>进入登录成功后，看看AI聊天会话，不行的话，你就直接说，现在已经登录成功，请重新自动发送推文。</p><p>![[Pasted image 20260209152110.png]]</p><p>如果进入到上面这个界面他没有继续自动点击了，你就点击我箭头的指向 [文章] =&gt; [撰写]，然后他就会自动进行了。看我下面的视频，重点注意视频中我的鼠标位置，其实是没动的。</p><p>![[output.mp4]]</p><p>怎么样？ 本地写完了一分钟就同步到推特后台，然后你可以再简单检查一下就可以发布了，真的很方便，需要的朋友可以去试试。</p><p>如果你遇到什么问题，可以随时给我留言，我会快速响应，实在不行我要是方便的时间， 你可以找我，我远程帮你搞定。</p>`,38)]))}const m=s(l,[["render",i]]);export{g as __pageData,m as default};
